[?2004lparser grammar SYsUParser;

options {
  tokenVocab=SYsULexer;
}

// Entry point
compilationUnit
    :   translationUnit? EOF
    ;

translationUnit
    :   externalDeclaration+
    ;

externalDeclaration
    :   functionDefinition
    |   declaration
    ;

// Function definition
functionDefinition
    :   declarationSpecifiers directDeclarator '(' parameterTypeList? ')' compoundStatement
    ;

// Declarations
declaration
    :   declarationSpecifiers initDeclaratorList? ';'
    ;

declarationSpecifiers
    :   declarationSpecifier+
    ;

declarationSpecifier
    :   typeSpecifier
    |   typeQualifier
    ;

typeSpecifier
    :   Int
    |   Void
    |   Const
    ;

typeQualifier
    :   Const
    ;

initDeclaratorList
[?2004h
